		UPDATE seat_table
		SET seat_status = 'HELD',
			user_id = #{userId},
            hold_at = NOW()
        WHERE show_id = #{showId}
          AND schedule_id = #{scheduleId}
          AND seat_label IN 

              #{label}

          AND (seat_status = 'AVAILABLE' OR (seat_status = 'HELD' AND hold_at < SUBTIME(NOW(), '0:5:0')))
